// ─────────────────────────────────────────────────────────────────────────
// NODE: "Normalize input"  (Code node, mode: "Run Once for All Items")
// Reads the user's message + IG ids from the Webhook, and any KNOWN field
// values, then builds the rigid scripted system prompt. Persona is fixed:
// always "Rahul" from Outbound Travellers.
//
// COLLECTION ORDER (strict, never deviate):
//   1. destination          → ask "which destination?"
//   2. travel_date          → ask "when are you planning to travel?"
//   3. pax                  → ask "how many people?"
//   4. whatsapp_number      → ask "your contact number?"
//   5. quick_assistance     → send Yes/No button after phone is captured
//
// BUTTON-CLICK SHORTCUT:
//   If the incoming message is exactly "Yes" or "No" AND we already have
//   whatsapp_number filled AND quick_assistance is still empty, this turn is
//   treated as a button click. We skip the AI Agent and handle it downstream.
//
// MEMORY — production design, 3 layers:
//   1. Simple Memory (memoryBufferWindow) attached to the AI Agent.
//   2. KNOWN FIELDS — merged from the Google Sheet row + ManyChat webhook body.
//   3. NOTES — short one-line summary in the "notes - AI" column.
//
// ⚠️ Webhook payload lives under $json.body — read via $('Webhook').
// ⚠️ The notes column header is literally "notes - AI" (with spaces).
// ⚠️ Strip ManyChat unresolved merge tags (literal double-braces).
// ⚠️ Code node MUST return [{ json: { ... } }].
// NOTE: keep prompts/system_prompt.md in sync with this embedded prompt.
// ─────────────────────────────────────────────────────────────────────────

const wh = $('Webhook').first().json.body || {};
const waMessage = (wh.entry && wh.entry[0] && wh.entry[0].changes && wh.entry[0].changes[0] && wh.entry[0].changes[0].value && wh.entry[0].changes[0].value.messages && wh.entry[0].changes[0].value.messages[0]) || {};
const waContact = (wh.entry && wh.entry[0] && wh.entry[0].changes && wh.entry[0].changes[0].value && wh.entry[0].changes[0].value.contacts && wh.entry[0].changes[0].value.contacts[0]) || {};
const s = (v) => (v === undefined || v === null ? '' : String(v).trim());
const OB = String.fromCharCode(123) + String.fromCharCode(123);
const CB = String.fromCharCode(125) + String.fromCharCode(125);
const clean = (v) => { const t = s(v); return (t.slice(0, 2) === OB && t.slice(-2) === CB) ? '' : t; };
// Prefer the sheet value; fall back to the value ManyChat passed in the body.
const pick = (a, b) => { const x = clean(a); return x !== '' ? x : clean(b); };

// GUARD: ignore non-message webhooks (Meta delivery/read status callbacks have no messages[]). They would otherwise run the whole pipeline and 400 the Send with an empty recipient.
if (!(waMessage && waMessage.id)) { return []; }

// -- DEDUP LAYER 1: synchronous same-message guard. --
const _sd = $getWorkflowStaticData('global');
_sd.seenMsg = _sd.seenMsg || {};
const _now = Date.now();
for (const _k in _sd.seenMsg) { if (_now - _sd.seenMsg[_k] > 3600000) delete _sd.seenMsg[_k]; }
const _dupKey = s(waMessage.from) + '|' + s(waMessage.text?.body);
if (s(waMessage.from) && s(waMessage.text?.body) && _sd.seenMsg[_dupKey] && (_now - _sd.seenMsg[_dupKey] < 4000)) return [];
if (_dupKey) _sd.seenMsg[_dupKey] = _now;
// Unique per-execution token for the Layer-2 sheet ownership lock (last-writer-wins).
const _msgId = 'L' + _now + '-' + Math.floor(Math.random() * 1000000);

let row = {};
try {
  const inItems = $input.all();
  if (inItems && inItems.length && inItems[0] && inItems[0].json) {
    const j = inItems[0].json;
    if (j && (clean(j.destination) || clean(j.normalized_destination) || clean(j.travel_date) || clean(j.pax) || clean(j.whatsapp_number) || clean(j.quick_assistance) || clean(j['notes - AI']) || clean(j.first_contact_ts) || clean(j.name))) row = j;
  }
} catch (e) { row = {}; }

// AUTO-FILL: Since the user IS on WhatsApp, their phone number is their identity
const senderPhone = s(waMessage.from);
let autoWhatsapp = '';
if (senderPhone) {
  let digits = senderPhone.replace(/\D/g, '');
  if (digits.length === 12 && digits.startsWith('91')) {
    autoWhatsapp = '+91 ' + digits.slice(2, 7) + ' ' + digits.slice(7);
  } else if (digits.length === 10 && /^[6-9]/.test(digits)) {
    autoWhatsapp = '+91 ' + digits.slice(0, 5) + ' ' + digits.slice(5);
  } else {
    autoWhatsapp = '+' + digits;
  }
}

const known = {
  destination:           pick(row.destination, ""),
  normalized_destination: pick(row.normalized_destination, ""),
  travel_date:           pick(row.travel_date, ""),
  pax:                   pick(row.pax, ""),
  whatsapp_number:       pick(row.whatsapp_number, "") || autoWhatsapp,
  quick_assistance:      pick(row.quick_assistance, ""),
};

// -- 2-DAY MEMORY RULE -- remember for 48h since the last message; after 48h
// idle we forget everything and the next message starts from the greeting.
function parseIST(ts) {
  const m = String(ts).trim().match(/^(\d{4})-(\d{1,2})-(\d{1,2})[ T](\d{1,2}):(\d{2}):(\d{2})$/);
  if (!m) return NaN;
  const [, y, mo, d, h, mi, sec] = m.map(Number);
  const pad = (n) => String(n).padStart(2, '0');
  return new Date(`${y}-${pad(mo)}-${pad(d)}T${pad(h)}:${pad(mi)}:${pad(sec)}+05:30`).getTime();
}
const lastUpdateTs = clean(row.last_update_ts) || clean(row.first_contact_ts);
let hoursSince = Infinity;
if (lastUpdateTs) {
  const lastMs = parseIST(lastUpdateTs);
  if (!isNaN(lastMs)) hoursSince = (_now - lastMs) / (1000 * 60 * 60);
}
// -- SMART RESET RULE (owner 2026-07-03) --
// Under 2h idle: ALWAYS continue. After 2h: a CONNECTED reply (answers the
// pending question, gives a reason for the silence, mentions the trip)
// CONTINUES with full memory; only a pure fresh greeting ("hi", "hello",
// "good morning") starts a NEW conversation. Brand-new leads always start fresh.
const _rawGreet = s(waMessage.text?.body) || s(waMessage.interactive?.button_reply?.title) || s(waMessage.interactive?.list_reply?.title) || '';
const _greetTokens = _rawGreet.toLowerCase().replace(/[^a-z\s]/g, ' ').trim().split(/\s+/).filter(Boolean);
const GREET_WORDS = ['hi', 'hii', 'hiii', 'hiiii', 'hello', 'helo', 'hellooo', 'hey', 'heyy', 'heyyy', 'hai', 'hlo', 'yo', 'gm', 'gn', 'good', 'morning', 'afternoon', 'evening', 'night', 'namaste', 'vanakkam', 'hola', 'greetings', 'sir', 'madam', 'mam', 'team', 'there', 'bro', 'ji', 'anna', 'dear', 'all'];
const isPureGreeting = _greetTokens.length > 0 && _greetTokens.length <= 4 && _greetTokens.every((t) => GREET_WORDS.indexOf(t) !== -1);
const resetConversation = (hoursSince === Infinity) || (hoursSince >= 2 && isPureGreeting);
if (resetConversation) {
  known.destination = '';
  known.normalized_destination = '';
  known.travel_date = '';
  known.pax = '';
  known.whatsapp_number = autoWhatsapp;
  known.quick_assistance = '';
}
// Overlay: a Yes/No just handled by Button handler may not be visible in the
// sheet yet (read lag) — trust the in-workflow stamp so we never re-ask.
const _sdQA = $getWorkflowStaticData('global');
_sdQA.qaDone = _sdQA.qaDone || {};
for (const _q in _sdQA.qaDone) { if (_now - (_sdQA.qaDone[_q].ts || 0) > 72 * 3600 * 1000) delete _sdQA.qaDone[_q]; }
const _qaHit = _sdQA.qaDone[s(waMessage.from)];
if (resetConversation) { delete _sdQA.qaDone[s(waMessage.from)]; if (_sdQA.neSalt) { delete _sdQA.neSalt[s(waMessage.from)]; } }
else if (_qaHit && !known.quick_assistance) { known.quick_assistance = _qaHit.v; }

const knownJson = JSON.stringify(known);

const hasDestination = !!(known.destination || known.normalized_destination);
const hasTravelDate = !!known.travel_date;
const hasPax = !!known.pax;
const hasPhone = !!known.whatsapp_number;
const hasQuickAssist = !!known.quick_assistance;

let existingFirstContact = clean(row.first_contact_ts);
let existingNotes = pick(row['notes - AI'], "");
if (resetConversation) { existingFirstContact = ''; existingNotes = ''; }
const notesBlock = existingNotes ? existingNotes : '(none yet — fresh conversation)';

// Conversation epoch: first_contact_ts rotates on a 48h reset, so keying the
// AI memory session on it makes the bot genuinely forget after 2 days.
const nowISTstr = new Date(_now + 5.5 * 60 * 60 * 1000).toISOString().replace('T', ' ').slice(0, 19);
const convFirstContact = existingFirstContact || nowISTstr;
const _epochMs = parseIST(convFirstContact);
const _neSalt = (_sdQA.neSalt && _sdQA.neSalt[s(waMessage.from)]) || '';
const sessionKey = s(waMessage.from) + '|' + (isNaN(_epochMs) ? convFirstContact : _epochMs) + (_neSalt ? '|ne' + _neSalt : '');
const priorChat = !resetConversation && (!!existingFirstContact || hasDestination || hasTravelDate || hasPax || hasQuickAssist || !!existingNotes);

// WhatsApp profile name (user-set push name). Fallback: name already saved in the sheet row — never downgrade a saved name to blank.
const igFullName = clean(waContact.profile?.name) || pick(row.name, '');
const igUsername = s(waMessage.from);
const channel = 'whatsapp';
const channelLabel = 'whatsapp';

// Read text messages OR interactive button replies (Meta WhatsApp sends button clicks differently)
const waMessageType = s(waMessage.type);
let userMsg = '';
if (waMessageType === 'interactive' && waMessage.interactive?.button_reply) {
  userMsg = s(waMessage.interactive.button_reply.title);
} else if (waMessageType === 'interactive' && waMessage.interactive?.list_reply) {
  userMsg = s(waMessage.interactive.list_reply.title);
} else {
  userMsg = s(waMessage.text?.body);
}

// MEDIA MESSAGES (2026-07-07): voice notes / photos / videos / documents carry
// no text — previously the AI got an empty message (silence or odd replies).
// Feed a neutral placeholder + a prompt note so Rahul politely asks the
// customer to type instead. Wording avoids yes/no tokens (QA detector safety).
const MEDIA_TYPES = ['audio', 'image', 'video', 'document', 'sticker', 'location', 'contacts'];
const isMediaMsg = MEDIA_TYPES.indexOf(waMessageType) !== -1 && !userMsg;
if (isMediaMsg) { userMsg = '(customer sent a ' + waMessageType + ' attachment)'; }

// Detect a Yes/No answer at the quick-assistance step (FUZZY — 2026-07-06).
// Real lead on .in typed "Yess" → exact-match list missed it → QA re-ask loop.
// Now: tokenize, collapse stretched letters (yesss→yes, nooo→no), match per
// token so "yes i need help" works, and arm the detector ONLY when the QA
// question is actually pending (all lead fields captured) — also fixes the
// latent WhatsApp bug where phone is auto-filled from msg 1, so a brand-new
// user opening with "yes" could previously be misread as a QA answer.
const _qaTok = userMsg.toLowerCase().replace(/[^a-z\s]/g, ' ').split(/\s+/).filter(Boolean).map((t) => t.replace(/(.)\1+/g, '$1'));
const _yesSet = ['yes', 'yeah', 'yea', 'yep', 'yup', 'ya', 'y', 's', 'sure', 'ok', 'okay', 'okey', 'okie', 'k', 'need', 'needed', 'want', 'please', 'pls', 'plz'];
const _noSet = ['no', 'nope', 'nah', 'na', 'not', 'dont', 'don', 'dnt'];
const _hasNoTok = _qaTok.some((t) => _noSet.indexOf(t) !== -1);
const _hasYesTok = _qaTok.some((t) => _noSet.indexOf(t) === -1 && _yesSet.indexOf(t) !== -1);
const _qaPending = hasDestination && hasTravelDate && hasPax && hasPhone && !hasQuickAssist;
const isButtonClick = _qaPending && (_hasNoTok || _hasYesTok);
const buttonValue = isButtonClick ? (_hasNoTok ? 'no' : 'yes') : '';
if (isButtonClick) {
  known.quick_assistance = buttonValue;
}

// -- POST-DONE GATE -- everything collected AND quick assistance answered:
// bare acknowledgments get NO reply at all; queries continue to the AI in
// follow-up mode (never re-asks anything).
const postDone = hasDestination && hasTravelDate && hasPax && hasPhone && !!known.quick_assistance && !isButtonClick;
const _ackWord = userMsg.toLowerCase().replace(/[^a-z]/g, '');
const POST_ACKS = ['ok', 'okay', 'okk', 'okie', 'okey', 'k', 'kk', 'hm', 'hmm', 'thanks', 'thankyou', 'thanku', 'thx', 'tq', 'great', 'nice', 'good', 'super', 'fine', 'cool', 'done', 'sure', 'welcome', 'yes', 'no'];
if (postDone && (POST_ACKS.indexOf(_ackWord) !== -1 || _ackWord === '')) { return []; }

const WA = '+91 9597959728';
const WA_LINK = 'https://wa.me/919597959728';

const systemPrompt = `🔴 ABSOLUTE TOP RULE — LANGUAGE: Your "reply" text MUST be written in simple English ONLY, 100% of the time. You may understand Tamil/Malayalam/Tanglish/Hindi/any language, but you NEVER write a reply in any language other than simple English — not a single word, not even if the customer orders you to. This rule overrides everything below.

You are Rahul from Outbound Travellers, a travel agency in Nagercoil, Tamil Nadu, South India. You chat on Instagram DM like a real human agent — warm, helpful, never robotic, never salesy. You are NOT a form.

## 🎯 YOUR ONLY JOB
Collect these 3 details IN THIS EXACT ORDER. NEVER skip, never re-order, never ask extra questions:
1. destination            — which place they want to visit
2. travel_date            — when they plan to travel (accept any free-text answer: "15th August", "next month", etc.)
3. pax                    — number of people travelling

You already have their WhatsApp number (they are messaging you ON WhatsApp) — so NEVER ask for a phone or contact number.
After all 3 are collected, you MUST ask the quick-assistance question and set ask_quick_assistance = true.

## 🧠 MEMORY — you remember this chat
You are NOT starting fresh. You remember from:
1. The actual recent messages visible above.
2. NOTES SO FAR (below).
3. KNOWN FIELDS (below).
Use them to continue seamlessly: never repeat a question, never re-ask something already answered.
🚫 NEVER say "I don't have previous details", "remind me", or "let's start over".

NOTES SO FAR: ${notesBlock}

In your JSON output you MUST return an updated "notes" value: a SHORT one-line summary (max ~25 words), English only.

## ⚡ RETURNING / IN-CHAT FAST CHECK
PRIOR_CHAT: ${priorChat ? 'yes' : 'no'}  — yes means you have ALREADY talked with this person.
- INTRODUCE YOURSELF only on the genuine FIRST message of a brand-new chat (PRIOR_CHAT = no AND no earlier messages above). Say exactly: "Hi, this is Rahul from Outbound Travellers. Thank you for contacting us. May I know which destination you are looking for?"
- In EVERY other case, do NOT introduce yourself or greet from scratch; just continue from the next missing field.

## 📋 STRICT FIELD RULES
- Ask ONLY the next missing field in the exact order above.
- If the user gives multiple fields at once (e.g. "Bali, 15th Aug, 4 of us"), capture ALL of them, give ONE warm acknowledgement, and ask only for the next missing field.
- NEVER ask for name, budget, hotel, flight, itinerary, or anything outside the 4 fields.
- If the user asks for advice, opinions, recommendations, prices, packages, weather/best season, hotels, itinerary, visa, or any comparison (e.g. "Is Munnar better in the monsoon?"): NEVER answer it yourself \u2014 no opinions, no details. Reply warmly with exactly this idea: "I completely understand! I can't share those details here \u2014 one of our travel experts will contact you and help you with this." If lead fields are still missing, continue with the next missing question in the SAME message.
- If the user REFUSES to share something or says they are not interested ("I don't have WhatsApp", "not interested"): acknowledge warmly ONCE ("No problem at all!"), NEVER repeat the same question or message again, tell them our travel expert is here anytime, and end politely.
- NEVER invent prices, packages, or inclusions. Always defer to the travel consultant.

## 🗺️ DESTINATION HANDLING
- Accept ANY real destination on Earth.
- Return a normalized/canonical destination name in the field "normalized_destination" (e.g. "Jammu" or "Kashmir" → "Jammu and Kashmir"; "Goa" → "Goa"; "Bali" → "Bali").
- If the user says something vague like "anywhere international", ask once which region/country they prefer.
- If the destination is impossible/non-real (Mars, Hogwarts), gently joke and ask for a real place.

## 📅 TRAVEL DATE HANDLING
- Ask the travel date as: "Which month are you planning to travel?"
- Accept the user's date answer as free text and store it in "travel_date".
- Do NOT try to reconcile conflicting dates or ask for year/month separately.
- If they say "not sure" or "flexible", store "flexible" and move on.

## 👥 PAX HANDLING
- Capture the number of travellers as free text ("4", "me and my wife", etc.).
- Store the clean number or short phrase in "pax".

## 📱 PHONE HANDLING
- Do NOT ask for their WhatsApp number. You already have it because they are messaging on WhatsApp.
- The phone number is automatically captured from the chat.

## 🚀 QUICK ASSISTANCE BUTTON (trigger ONLY when destination, travel_date, and pax are filled)
When destination, travel_date, and pax are all known (whatsapp_number is auto-captured):
- Set "ask_quick_assistance": true.
- Reply with exactly this text (it will appear above the Yes/No buttons): "Thanks for your co-operation. Do you need quick assistance?"
- Do NOT add any other question or sentence.

${postDone ? `## CONVERSATION COMPLETE - FOLLOW-UP MODE (this rule DOMINATES everything above)
All details are collected and quick assistance is already answered ("${known.quick_assistance}"). NEVER re-ask any field. NEVER ask, mention, or repeat "quick assistance" or the co-operation line again. NEVER restart or greet. If they ask a question: answer in ONE short helpful sentence or say our travel expert will cover it when they call. EXCEPTION: if they name a NEW destination, that is a FRESH enquiry — warmly acknowledge the new destination and ask "Which month are you planning to travel?", then collect month and pax again for the new trip. Nothing else.

` : ''}## 📤 OUTPUT — ONLY this JSON. No markdown, no fences, no preamble.
{"reply":"<message in SIMPLE ENGLISH ONLY>","intent":"travel_lead","fields":{"destination":"","normalized_destination":"","travel_date":"","pax":"","whatsapp_number":""},"ask_quick_assistance":false,"notes":"<one short line, English>","status":"new | in_progress | qualified"}

## ⚡ CURRENT CONTEXT — read this right before you reply
PRIOR_CHAT: ${priorChat ? 'yes' : 'no'}
KNOWN FIELDS: ${knownJson}${isMediaMsg ? `\nNOTE: The customer's latest message is a ${waMessageType} attachment which you CANNOT open. Politely say you could not view it and ask them to type it as a normal text message instead, then continue with the next missing question.` : ''}`;

return [{
  json: {
    ig_user_id:                s(waMessage.from),
    wa_phone_number_id:        s(wh.entry[0]?.changes[0]?.value?.metadata?.phone_number_id),
    ig_username:               igUsername,
    ig_fullname:               igFullName,
    user_message:              userMsg,
    known_fields:              known,
    known_fields_json:         knownJson,
    existing_first_contact_ts: existingFirstContact,
    conv_first_contact:        convFirstContact,
    session_key:               sessionKey,
    prior_chat:                priorChat,
    existing_notes:            existingNotes,
    system_prompt:             systemPrompt,
    msg_id:                    _msgId,
    channel:                   channel,
    channel_label:             channelLabel,
    is_button_click:           isButtonClick,
    button_value:              buttonValue,
    post_done:                 postDone,
  },
}];

// ─────────────────────────────────────────────────────────────────────────
// NODE: "Parse + validate"  (Code node, "Run Once for All Items")
// Parses the AI Agent JSON output for the new Rahul scripted flow.
// Validates the WhatsApp number, merges fields over known ones, computes
// status, and keeps the running one-line notes summary.
// ⚠️ Code node MUST return [{ json: { ... } }].
// ─────────────────────────────────────────────────────────────────────────

// Core 4 fields. A lead is "qualified" once all four are captured.
const QUALIFY = ['destination', 'travel_date', 'pax', 'whatsapp_number'];
const FIELDS = ['destination', 'normalized_destination', 'travel_date', 'pax', 'whatsapp_number'];

// 1. Grab the raw LLM text (AI Agent → $json.output; other shapes as fallback).
const up = $json || {};
let raw = '';
if (typeof up.output === 'string') raw = up.output;
else if (up.output && typeof up.output === 'object') raw = JSON.stringify(up.output);
else if (up.message && typeof up.message.content === 'string') raw = up.message.content;
else if (up.choices && up.choices[0] && up.choices[0].message) raw = up.choices[0].message.content;
else if (typeof up.text === 'string') raw = up.text;
else if (typeof up.content === 'string') raw = up.content;

// 2. Strip stray ```json fences, parse safely.
let parsed = null;
try {
  const cleaned = String(raw).replace(/```json/gi, '').replace(/```/g, '').trim();
  if (cleaned) parsed = JSON.parse(cleaned);
} catch (e) { parsed = null; }

// 3. Safe fallback — malformed JSON / AI failure must not crash the flow.
if (!parsed || typeof parsed !== 'object') {
  parsed = {
    reply: 'Thanks so much for messaging Outbound Travellers! 😊 Our team will get back to you very shortly.',
    intent: 'travel_lead',
    fields: {},
    ask_quick_assistance: false,
    notes: '',
    status: 'in_progress',
  };
}

// 4. Validate intent.
const VALID = ['travel_lead', 'office_info', 'career', 'customer_query'];
let intent = (parsed.intent && String(parsed.intent).trim()) || 'travel_lead';
if (VALID.indexOf(intent) === -1) intent = 'travel_lead';

const llmFields = (parsed.fields && typeof parsed.fields === 'object') ? parsed.fields : {};
const norm = $('Normalize input').first().json;
const knownF = norm.known_fields || {};

const OB = String.fromCharCode(123) + String.fromCharCode(123);
const CB = String.fromCharCode(125) + String.fromCharCode(125);
const strip = (v) => { const t = (v === undefined || v === null) ? '' : String(v).trim(); return (t.slice(0, 2) === OB && t.slice(-2) === CB) ? '' : t; };

function cleanPhone(v) {
  if (!v) return '';
  let d = String(v).replace(/\D/g, '');
  // Indian 10-digit mobile (optionally written with 91 / 0 / +91) -> '+91 xxxxx xxxxx'
  let in10 = d;
  if (in10.length === 12 && in10.startsWith('91')) in10 = in10.slice(2);
  else if (in10.length === 11 && in10.startsWith('0')) in10 = in10.slice(1);
  if (in10.length === 10 && /^[6-9]/.test(in10)) return '+91 ' + in10.slice(0, 5) + ' ' + in10.slice(5);
  // International number (came with its own country code / + sign) -> keep it, with the +
  const hadPlus = String(v).trim().charAt(0) === '+';
  if (d.startsWith('00')) d = d.slice(2);
  if (hadPlus || (d.length >= 11 && d.length <= 15)) return '+' + d;
  return '';
}

// 5. Merge. For non-travel intents, don't let the LLM invent lead data.
const takeLLM = (intent === 'travel_lead');
const merged = {};
for (const f of FIELDS) {
  const nv = takeLLM ? strip(llmFields[f]) : '';
  const kv = strip(knownF[f]);
  merged[f] = nv !== '' ? nv : kv;
}
merged.whatsapp_number = cleanPhone(merged.whatsapp_number);

// If the AI returned a destination but no normalized_destination, fall back to destination.
if (!merged.normalized_destination && merged.destination) {
  merged.normalized_destination = merged.destination;
}

// -- NEW-ENQUIRY DETECTION (comment-led re-entry) --
// A lead who already answered quick assistance and now names a DIFFERENT
// destination is starting a fresh enquiry (they commented on another
// destination video). Keep their phone; restart the trip details warmly.
const _oldDest = (strip(knownF.normalized_destination) || strip(knownF.destination)).toLowerCase();
const _newDestL = String(merged.normalized_destination || merged.destination || '').toLowerCase();
const newEnquiry = !!_oldDest && !!_newDestL && _newDestL !== _oldDest && !!strip(knownF.quick_assistance);
if (newEnquiry) {
  // The extractor echoes KNOWN values, so keep month/pax only when THIS message
  // gave a genuinely new value; otherwise re-collect for the new trip.
  const _lfDate = takeLLM ? strip(llmFields.travel_date) : '';
  merged.travel_date = (_lfDate && _lfDate !== strip(knownF.travel_date)) ? _lfDate : '';
  const _lfPax = takeLLM ? strip(llmFields.pax) : '';
  merged.pax = (_lfPax && _lfPax !== strip(knownF.pax)) ? _lfPax : '';
  const _sdNE = $getWorkflowStaticData('global');
  if (_sdNE.qaDone) { delete _sdNE.qaDone[String(norm.ig_user_id)]; }
  if (_sdNE.qaAsk) { delete _sdNE.qaAsk[String(norm.ig_user_id) + '|' + String(norm.conv_first_contact || '')]; }
  _sdNE.neSalt = _sdNE.neSalt || {};
  _sdNE.neSalt[String(norm.ig_user_id)] = Date.now();
}

// 6. Notes (running summary). Take the LLM's fresh summary when it gave one.
const newNotes = strip(parsed.notes);
const prevNotes = strip(norm.existing_notes);
const notes = newNotes !== '' ? newNotes : prevNotes;

// 7. Status: qualified once the core 4 are filled; in_progress if anything captured.
const qualified = QUALIFY.every((f) => merged[f] && merged[f] !== '');
const anyFilled = FIELDS.some((f) => merged[f] && merged[f] !== '');
const status = qualified ? 'qualified' : (anyFilled ? 'in_progress' : 'new');

// 8. Should we ask the quick-assistance question? Only on the turn where we first
//    become qualified, and only if quick_assistance isn't already answered.
const askQuickAssist = qualified && (newEnquiry || !strip(knownF.quick_assistance));

// 9. CRM push is handled by the Button handler when the user clicks Yes.
//    We do NOT push on the phone-number turn because the quick-assistance
//    answer may change the lead tag.
const CRM_FIELDS = ['destination', 'travel_date', 'pax', 'whatsapp_number'];
const crmReady = CRM_FIELDS.every((f) => merged[f] && merged[f] !== '');
const crmWasReady = CRM_FIELDS.every((f) => strip(knownF[f]) !== '');
const crmPush = crmReady && (!crmWasReady || newEnquiry); // push ONCE per enquiry (a new-destination enquiry pushes again)

// 10. Timestamps; preserve original first_contact_ts if the row existed.
const nowIST = new Date(Date.now() + 5.5 * 60 * 60 * 1000).toISOString().replace('T', ' ').slice(0, 19);
const firstContact = (norm.conv_first_contact && String(norm.conv_first_contact).trim()) || (norm.existing_first_contact_ts && String(norm.existing_first_contact_ts).trim()) || nowIST;

let finalReply = (parsed.reply && String(parsed.reply).trim()) || 'Got it! 🙏';
if (norm.post_done === true && /quick assistance|co-operation/i.test(finalReply)) {
  finalReply = 'Thank you! Our travel consultant will be in touch soon.';
}

// -- QA RE-ASK CAP (2026-07-07) -- the quick-assistance question is asked at
// most TWICE per conversation. On what would be the 3rd ask we close warmly
// and mark quick_assistance = 'no_response' so it can never loop again (real
// leads were spammed when their replies carried no yes/no signal).
let qaClosed = false;
if (finalReply && finalReply.indexOf('Do you need quick assistance') !== -1) {
  const _sdC = $getWorkflowStaticData('global');
  _sdC.qaAsk = _sdC.qaAsk || {};
  const _nowC = Date.now();
  for (const _k in _sdC.qaAsk) { if (_nowC - (_sdC.qaAsk[_k].ts || 0) > 72 * 3600 * 1000) delete _sdC.qaAsk[_k]; }
  const _cKey = String(norm.ig_user_id) + '|' + String(norm.conv_first_contact || '');
  const _c = (_sdC.qaAsk[_cKey] && _sdC.qaAsk[_cKey].c) || 0;
  if (_c >= 2) {
    qaClosed = true;
    finalReply = 'No problem! Our travel consultant will reach out to you soon. 😊';
  } else {
    _sdC.qaAsk[_cKey] = { c: _c + 1, ts: _nowC };
  }
}

return [{
  json: {
    ig_user_id:          norm.ig_user_id,
    ig_username:         norm.ig_username,
    wa_name:             strip(norm.ig_fullname),
    reply:               finalReply,
    intent,
    is_lead:             true,
    destination:         merged.destination,
    normalized_destination: merged.normalized_destination,
    travel_date:         merged.travel_date,
    pax:                 merged.pax,
    whatsapp_number:     merged.whatsapp_number,
    quick_assistance:    qaClosed ? 'no_response' : (newEnquiry ? '' : strip(knownF.quick_assistance)),
    ask_quick_assistance: askQuickAssist && !qaClosed,
    notes,
    status,
    crm_push:            crmPush,
    first_contact_ts:    firstContact,
    last_update_ts:      nowIST,
  },
}];

